def read_orders():
    orders = []
    try:
        with open(os.path.join(DATA_DIR, 'order.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split(',')
                if len(parts) < 6:
                    continue
                # orderID, custName, orderDate, amountTotal, status, shippingAddr (shippingAddr may have multiple parts)
                order = {
                    'orderID': parts[0],
                    'custName': int(parts[1]),
                    'orderDate': parts[2],
                    'amountTotal': parts[3],
                    'status': int(parts[4]),
                    'shippingAddr': parts[5:]  # list
                }
                orders.append(order)
    except FileNotFoundError:
        pass
    return orders


